var (
	ErrAccountNotFound     = errors.New("account not found")
	ErrInsufficientFunds   = errors.New("insufficient funds")
	ErrInvalidAmount       = errors.New("invalid amount")
	ErrInvalidTransaction  = errors.New("invalid transaction")
)

type TransactionType int

const (
	Deposit TransactionType = iota
	Withdraw
)

type Transaction struct {
	AccountID string
	Type      TransactionType
	Amount    int64
}

type Bank struct {
	mu       sync.RWMutex
	balances map[string]int64
}

func NewBank(initial map[string]int64) *Bank {
	cp := make(map[string]int64, len(initial))
	for k, v := range initial {
		cp[k] = v
	}
	return &Bank{balances: cp}
}

func (b *Bank) Balance(accountID string) (int64, error) {
	b.mu.RLock()
	defer b.mu.RUnlock()
	v, ok := b.balances[accountID]
	if !ok {
		return 0, ErrAccountNotFound
	}
	return v, nil
}

func (b *Bank) Apply(tx Transaction) (int64, error) {
	if tx.AccountID == "" {
		return 0, ErrInvalidTransaction
	}
	if tx.Amount <= 0 {
		return 0, ErrInvalidAmount
	}

	b.mu.Lock()
	defer b.mu.Unlock()

	cur, ok := b.balances[tx.AccountID]
	if !ok {
		return 0, ErrAccountNotFound
	}

	switch tx.Type {
	case Deposit:
		cur += tx.Amount
	case Withdraw:
		if cur < tx.Amount {
			return cur, ErrInsufficientFunds
		}
		cur -= tx.Amount
	default:
		return 0, ErrInvalidTransaction
	}

	b.balances[tx.AccountID] = cur
	return cur, nil
}

func (b *Bank) ProcessTransactionsConcurrently(txs []Transaction, workers int) []error {
	if workers <= 0 {
		workers = 1
	}

	errs := make([]error, len(txs))
	jobs := make(chan int)

	var wg sync.WaitGroup
	wg.Add(workers)
	for w := 0; w < workers; w++ {
		go func() {
			defer wg.Done()
			for i := range jobs {
				_, err := b.Apply(txs[i])
				errs[i] = err
			}
		}()
	}

	for i := range txs {
		jobs <- i
	}
	close(jobs)
	wg.Wait()
	return errs
}

